solution_code:
#define _DEFAULT_SOURCE
#include <stdio.h>
#include <unistd.h>
#include <string.h>

typedef struct Header {
    size_t size;
    int is_free;
    struct Header *next;
} Header;

#define HEADER_SIZE sizeof(Header)
static Header *free_list = NULL;

Header *find_free(size_t size) {
    Header *curr = free_list;
    while (curr) {
        if (curr->is_free && curr->size >= size) return curr;
        curr = curr->next;
    }
    return NULL;
}

void *my_malloc(size_t size) {
    if (size == 0) return NULL;
    Header *h = find_free(size);
    if (h) { h->is_free = 0; return (void *)(h + 1); }
    void *block = sbrk(HEADER_SIZE + size);
    if (block == (void *)-1) return NULL;
    h = (Header *)block;
    h->size = size; h->is_free = 0; h->next = free_list; free_list = h;
    return (void *)(h + 1);
}

void my_free(void *ptr) {
    if (!ptr) return;
    Header *h = (Header *)ptr - 1;
    h->is_free = 1;
}

int main(void) {
    int *a = my_malloc(4*sizeof(int));
    int *b = my_malloc(2*sizeof(int));
    char *c = my_malloc(16);
    for (int i = 0; i < 4; i++) a[i] = (i+1)*10;
    b[0] = 100; b[1] = 200; strcpy(c, "sbrk alloc");
    printf("a:"); for (int i = 0; i < 4; i++) printf(" %d", a[i]); printf("\n");
    printf("b: %d %d\n", b[0], b[1]);
    printf("c: %s\n", c);
    printf("HEADER_SIZE = %zu\n", HEADER_SIZE);
    my_free(b);
    int *d = my_malloc(2*sizeof(int));
    d[0] = 999;
    printf("d (reuse b): %d\n", d[0]);
    return 0;
}

